def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            base = ratio ** 5 + (capacity % 5) * 3.7
            sum_series = 0.0
            for x in range(1, int(capacity) + 3):
                if x % 3 == 0:
                    sum_series += np.exp(-x / (ratio + epsilon)) * np.sqrt(x + ratio)
                elif x % 2 == 0:
                    sum_series -= np.sin(ratio * x)
                else:
                    sum_series += np.log(x**2 + ratio * 2 + 1)
            priority = base + sum_series
            if capacity % 4 == 0:
                priority *= 1.25
            else:
                priority /= 1.1
        elif 2 < ratio <= 3:
            priority = np.tanh(ratio) * np.log(capacity + 2) * ratio ** 3
            for y in range(1, int(item) + 5):
                if y % 4 == 0:
                    priority += (y ** 2) / (capacity + 1)
                else:
                    priority -= np.power(y, 1.5) / (item + epsilon)
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 1)
            acc = 1.0
            for m in range(1, int(item) + 1):
                if m % 3 == 0:
                    priority += (m / (capacity + 1)) ** 2
                else:
                    priority -= m / (item + epsilon)
                if m % 5 == 0:
                    acc *= 1.05
            priority *= acc
            priority = max(priority, 0)
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon)
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + n / (capacity + 1))
                if factor > 7:
                    break
            priority *= factor
            if capacity % 2 == 0:
                priority += np.sqrt(capacity) / (ratio + epsilon)
            else:
                priority -= np.log(ratio + 1)
        elif 0.1 < ratio <= 0.5:
            total = 0.0
            for j in range(1, int(capacity) + 1):
                val = (ratio ** j) / (j + epsilon)
                if j % 2 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.5
            adjustment = 0.0
            for q in range(1, int(capacity / 2) + 2):
                if q % 2 == 1:
                    adjustment += np.cos(ratio * q)
                else:
                    adjustment -= np.sin(capacity / (q + epsilon))
            priority += adjustment / (capacity + 1)
        else:
            priority = 0.5 + ratio * 2
            for h in range(1, 10):
                if h % 3 == 0:
                    priority += np.tanh(h * ratio)
                else:
                    priority -= np.arctan(h / (capacity + epsilon))
            if capacity < 5:
                priority *= 0.8
            else:
                priority *= 1.1
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 2):
                if p % 2 == 0:
                    penalty += np.log(p + 2)
                else:
                    penalty -= p * 0.15
                if p % 5 == 0:
                    penalty += np.sqrt(p)
            penalty = max(penalty, 0)
            priority += penalty
        if priority < 0:
            priority = 0.0
        priorities[i] = priority
    return priorities
